import{c as t,Q as a,j as s,m as n}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Bootstrap Guide","description":"","frontmatter":{},"headers":[],"relativePath":"bootstrap-setup.md","filePath":"bootstrap-setup.md","lastUpdated":1778829542000}'),o={name:"bootstrap-setup.md"};function i(p,e,l,r,d,c){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="bootstrap-guide" tabindex="-1">Bootstrap Guide <a class="header-anchor" href="#bootstrap-guide" aria-label="Permalink to &quot;Bootstrap Guide&quot;">​</a></h1><p>One-time setup to configure Zitadel for Exto Console. Run this once per environment (local, staging, production). The script is idempotent — safe to re-run.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Zitadel running and accessible (e.g. <code>http://localhost:8080</code>)</li><li>Go 1.25+ installed (to run the bootstrap script)</li></ul><h2 id="_1-create-a-bootstrap-admin-user-in-zitadel" tabindex="-1">1. Create a bootstrap admin user in Zitadel <a class="header-anchor" href="#_1-create-a-bootstrap-admin-user-in-zitadel" aria-label="Permalink to &quot;1. Create a bootstrap admin user in Zitadel&quot;">​</a></h2><ol><li>Open Zitadel Console (<code>http://localhost:8080/ui/console/</code>)</li><li><strong>Users &gt; New &gt; Machine User</strong><ul><li>Username: <code>console-admin</code></li><li>Access Token Type: JWT</li></ul></li><li><strong>Memberships &gt; Add IAM membership &gt; IAM_OWNER</strong> role</li><li><strong>Personal Access Tokens &gt; New</strong> — copy the token</li></ol><h2 id="_2-create-the-bootstrap-input-file" tabindex="-1">2. Create the bootstrap input file <a class="header-anchor" href="#_2-create-the-bootstrap-input-file" aria-label="Permalink to &quot;2. Create the bootstrap input file&quot;">​</a></h2><p>Create <code>.bootstrap-input.env</code> in the project root:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ZITADEL_URL=http://localhost:8080</span></span>
<span class="line"><span>ZITADEL_PAT=&lt;paste-the-pat-here&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Optional — defaults shown:</span></span>
<span class="line"><span># CONSOLE_URL=http://localhost:5174</span></span>
<span class="line"><span># DEVELOPMENT_MODE=true</span></span></code></pre></div><p>For production: set <code>ZITADEL_URL</code> to your prod Zitadel, <code>CONSOLE_URL</code> to the real Console URL, and <code>DEVELOPMENT_MODE=false</code>.</p><h2 id="_3-run-bootstrap" tabindex="-1">3. Run bootstrap <a class="header-anchor" href="#_3-run-bootstrap" aria-label="Permalink to &quot;3. Run bootstrap&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootstrap</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or: go run ./scripts/bootstrap/</span></span></code></pre></div><p>Output (first run):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Connecting to Zitadel at http://localhost:8080 (developmentMode=true) ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✓ Admin org: ZITADEL (362930185718267907)</span></span>
<span class="line"><span>✓ Created project &#39;Exto Instances&#39;: 363006148858609667</span></span>
<span class="line"><span>✓ Created machine user &#39;console-worker&#39;: 363006148900814851</span></span>
<span class="line"><span>✓ Granted console-worker IAM Owner</span></span>
<span class="line"><span>✓ Generated client credentials for console-worker</span></span>
<span class="line"><span>✓ Created Console Portal OIDC app: appId=... clientId=...</span></span>
<span class="line"><span>✓ Set Zitadel label policy to light theme</span></span>
<span class="line"><span>✓ Got signing key from Zitadel</span></span>
<span class="line"><span>✓ Created Zitadel webhook target → http://localhost:5174/internal/zitadel-events</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Bootstrap complete. Values written to .bootstrap.env</span></span></code></pre></div><p>Output (re-run — existing resources are reused):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Admin org: ZITADEL (362930185718267907)</span></span>
<span class="line"><span>✓ Reusing existing project &#39;Exto Instances&#39;: 363006148858609667</span></span>
<span class="line"><span>✓ Reusing machine user &#39;console-worker&#39;: 363006148900814851</span></span>
<span class="line"><span>✓ Granted console-worker IAM Owner</span></span>
<span class="line"><span>✓ Skipping client secret generation — console-worker already exists (use existing credentials)</span></span>
<span class="line"><span>✓ Reusing existing Console Portal app: appId=... clientId=...</span></span>
<span class="line"><span>✓ Set Zitadel label policy to light theme</span></span>
<span class="line"><span>✓ Reusing existing webhook target &#39;console-profile-sync&#39;: ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Bootstrap complete. Values written to .bootstrap.env</span></span></code></pre></div><h2 id="_4-what-bootstrap-creates" tabindex="-1">4. What bootstrap creates <a class="header-anchor" href="#_4-what-bootstrap-creates" aria-label="Permalink to &quot;4. What bootstrap creates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Resource</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Exto Instances</strong> project</td><td>Groups all instance OIDC apps under one project</td></tr><tr><td><strong>console-worker</strong> machine user</td><td>Service account with IAM_OWNER for Zitadel Management API calls. <strong>Access Token Type must be JWT</strong> — opaque tokens will fail JWKS validation on instances.</td></tr><tr><td><strong>Console Portal</strong> OIDC app</td><td>PKCE SPA app for the Console frontend (no client secret — public client)</td></tr><tr><td>Light theme label policy</td><td>Matches Console&#39;s login page styling</td></tr><tr><td><strong>console-profile-sync</strong> webhook target</td><td>REST webhook with JSON payload type for user profile sync events</td></tr><tr><td>Webhook executions</td><td>Triggers on <code>user.human.profile.changed</code>, <code>user.human.email.changed</code>, <code>user.deactivated</code>, <code>user.reactivated</code></td></tr></tbody></table><h2 id="_5-bootstrap-output" tabindex="-1">5. Bootstrap output <a class="header-anchor" href="#_5-bootstrap-output" aria-label="Permalink to &quot;5. Bootstrap output&quot;">​</a></h2><p>Results are written to <code>.bootstrap.env</code>:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ZITADEL_ISSUER=http://localhost:8080</span></span>
<span class="line"><span>ZITADEL_API_URL=http://localhost:8080</span></span>
<span class="line"><span>ZITADEL_ADMIN_ORG_ID=&lt;org-id&gt;</span></span>
<span class="line"><span>EXTOID_PROJECT_ID=&lt;project-id&gt;</span></span>
<span class="line"><span>CONSOLE_SERVICE_CLIENT_ID=&lt;client-id&gt;</span></span>
<span class="line"><span>CONSOLE_SERVICE_CLIENT_SECRET=&lt;secret&gt;</span></span>
<span class="line"><span>CONSOLE_PORTAL_CLIENT_ID=&lt;client-id&gt;</span></span>
<span class="line"><span>ZITADEL_WEBHOOK_SECRET=&lt;signing-key-from-zitadel&gt;</span></span></code></pre></div><p>Copy these values into your deployment environment (<code>.env</code>, K8s secrets, etc.).</p><p><strong>Note:</strong> On re-runs, <code>CONSOLE_SERVICE_CLIENT_ID</code>, <code>CONSOLE_SERVICE_CLIENT_SECRET</code>, and <code>ZITADEL_WEBHOOK_SECRET</code> are omitted if the resources already existed (the secret/key cannot be retrieved after initial creation).</p><h2 id="_6-idempotency-details" tabindex="-1">6. Idempotency details <a class="header-anchor" href="#_6-idempotency-details" aria-label="Permalink to &quot;6. Idempotency details&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Resource</th><th>First run</th><th>Re-run</th></tr></thead><tbody><tr><td>Project</td><td>Created</td><td>Reused (matched by name)</td></tr><tr><td>Machine user</td><td>Created</td><td>Reused (matched by username)</td></tr><tr><td>Client credentials</td><td>Generated (rotates secret)</td><td><strong>Skipped</strong> — avoids invalidating existing deployments</td></tr><tr><td>OIDC app</td><td>Created</td><td>Reused (matched by name + project)</td></tr><tr><td>Webhook target</td><td>Created (returns signing key)</td><td><strong>Skipped</strong> — signing key cannot be retrieved</td></tr><tr><td>Webhook executions</td><td>Created</td><td>Skipped (target already exists)</td></tr></tbody></table><h2 id="_7-delete-the-bootstrap-admin" tabindex="-1">7. Delete the bootstrap admin <a class="header-anchor" href="#_7-delete-the-bootstrap-admin" aria-label="Permalink to &quot;7. Delete the bootstrap admin&quot;">​</a></h2><p>After Console is running and verified, delete the <code>console-admin</code> machine user from the Zitadel Console. The PAT is a privileged credential and is not needed at runtime.</p><h2 id="production-bootstrap" tabindex="-1">Production bootstrap <a class="header-anchor" href="#production-bootstrap" aria-label="Permalink to &quot;Production bootstrap&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># .bootstrap-input.env for production</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ZITADEL_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://auth.yourdomain.com</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ZITADEL_PAT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">prod-pat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONSOLE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://console.yourdomain.com</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEVELOPMENT_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">false</span></span></code></pre></div><p>Then run <code>make bootstrap</code> as normal. <code>DEVELOPMENT_MODE=false</code> ensures OIDC apps require HTTPS redirect URIs.</p><h2 id="file-layout" tabindex="-1">File layout <a class="header-anchor" href="#file-layout" aria-label="Permalink to &quot;File layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.bootstrap-input.env   # Bootstrap inputs (ZITADEL_URL, ZITADEL_PAT) — git-ignored</span></span>
<span class="line"><span>.bootstrap.env         # Bootstrap outputs (copy into deployment env) — git-ignored</span></span></code></pre></div>`,32)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
